import React from "react";
import { Helmet } from "react-helmet-async";
import "./Css/SupportPage.css";
import SEO from "../components/SEO";

const KOFI_EMBED_URL =
  "https://ko-fi.com/quickpronounce/?hidefeed=true&widget=true&embed=true&preview=true";
const UPI_LINK =
  "upi://pay?pa=ankitsharma93154@okicici&pn=QuickPronounce&cu=INR&tn=Support%20QuickPronounce";

const Support = () => {
  const handleUpiPayment = () => {
    window.location.href = UPI_LINK;
  };

  return (
    <div className="support-page" id="support-page">
      <SEO
        title="Support QuickPronounce | UPI, PayPal, Debit & Credit Card"
        description="QuickPronounce is a free, independently maintained pronunciation tool built by Ankit. Support via Ko-fi, PayPal, cards, or UPI to help keep it free and improve it over time."
        path="/support"
        ogType="website"
        image="https://www.quickpronounce.site/og-preview.png"
        ogTitle="Support QuickPronounce"
        ogDescription="Help keep QuickPronounce free and independently maintained through Ko-fi, PayPal, cards, or UPI."
      />

      <Helmet>
        <meta property="og:site_name" content="QuickPronounce" />

        <script type="application/ld+json">
          {JSON.stringify({
            "@context": "https://schema.org",
            "@type": "WebPage",
            name: "Support QuickPronounce",
            url: "https://www.quickpronounce.site/support",
            description:
              "Support QuickPronounce with Ko-fi, PayPal, cards, or UPI while keeping the tool free for everyone.",
            isPartOf: {
              "@type": "WebSite",
              name: "QuickPronounce",
              url: "https://www.quickpronounce.site",
            },
          })}
        </script>
      </Helmet>

      <div className="support-page__inner">
        <section className="support-page__hero">
          <p className="support-page__eyebrow">Built with care by Ankit</p>
          <h1>
            Helping QuickPronounce stay free for learners everywhere{" "}
            <span className="support-page__heart">❤</span>
          </h1>
          <p>
            Hi, I&apos;m Ankit, the solo developer behind QuickPronounce. I
            built it to make pronunciation help feel instant, free, and
            accessible without sign-ups or friction. The site is independently
            maintained, and while ads help cover part of the operating costs,
            donations make it possible to keep QuickPronounce free and keep
            improving it over time. If the tool has been useful to you, a little
            support means a lot.
          </p>
        </section>

        <section
          className="support-page__callout support-card"
          aria-label="Why support QuickPronounce"
        >
          <h2>Why support matters</h2>
          <p>
            Ads help with part of the running costs, but donations directly fund
            pronunciation API usage, hosting, infrastructure, new features, and
            ongoing maintenance. That support helps QuickPronounce stay free for
            everyone, now and in the future.
          </p>
          <p className="support-card__trust-note">
            Payments are securely processed by Ko-fi, and QuickPronounce never
            stores your payment information.
          </p>
        </section>

        <section className="support-page__grid" aria-label="Support options">
          <article className="support-card support-card--featured">
            <div className="support-card__heading-row">
              <h2>Ko-fi donation widget</h2>
              <span className="support-card__badge">PayPal + cards</span>
            </div>
            <p>
              Donate directly on the page using the official Ko-fi widget. It
              supports PayPal, debit cards, and credit cards without sending you
              away from the site.
            </p>
            <div
              className="support-card__embed-frame"
              aria-label="Ko-fi donation widget"
            >
              <iframe
                title="Ko-fi donation widget for QuickPronounce"
                src={KOFI_EMBED_URL}
                loading="lazy"
                referrerPolicy="no-referrer-when-downgrade"
                className="support-card__kofi-iframe"
              />
            </div>
            <p className="support-card__hint">
              Ko-fi securely handles checkout, and QuickPronounce never stores
              your payment details.
            </p>
          </article>

          <article className="support-card">
            <div className="support-card__heading-row">
              <h2>UPI (India)</h2>
              <span className="support-card__badge">Fast on mobile</span>
            </div>
            <p>
              Scan the QR code on desktop or tap the button on your phone to
              open Google Pay, PhonePe, Paytm, BHIM, or another UPI app.
            </p>
            <img
              src="/GooglePay_QR.png"
              alt="UPI QR code to support QuickPronounce"
              width="320"
              height="320"
              className="support-card__qr"
              loading="lazy"
              decoding="async"
            />
            <button
              type="button"
              onClick={handleUpiPayment}
              className="support-card__button support-card__button--full"
              aria-label="Pay with UPI for QuickPronounce"
            >
              Pay with UPI
            </button>
            <p className="support-card__hint">
              On desktop, the QR code is the easiest way to pay. On mobile, the
              UPI button opens your preferred app through a deep link.
            </p>
          </article>
        </section>

        <section
          className="support-page__banner"
          aria-label="Thank you message"
        >
          <h2>Every Contribution Matters ❤️</h2>
          <p>
            Thank you for donating, sharing QuickPronounce with others,
            reporting bugs, and sending feedback. Every form of support helps
            improve the experience for learners around the world.
          </p>
        </section>

        <section
          className="support-page__support-note support-card"
          aria-label="Support note"
        >
          <h2>Built with ❤️ by Ankit</h2>
          <p>
            QuickPronounce exists to make pronunciation practice easier for
            anyone who wants a fast, reliable, and free learning tool.
          </p>
        </section>
      </div>
    </div>
  );
};

export default Support;
